1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
8	const LOYALTY_MULTIPLIER = 0.8;
9	const ADMIN_FEE = 5;
10	
11	const BASE_PRICE: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	};
17	
18	function itemModifierMultiplier(item: Item): number {
19	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
20	  const highEnchantment =
21	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
22	  return cursed * highEnchantment;
23	}
24	
25	// MHPCO always rounds the euro value of a discounted/loaded price upward
26	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
27	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
28	// bumped up a euro by a 110.00000000000001 representation.
29	function ceilInMhpcoFavor(value: number): number {
30	  return Math.ceil(Number(value.toFixed(10)));
31	}
32	
33	export function runScenario(scenario: unknown): unknown {
34	  const { customer, steps } = scenario as Scenario;
35	  const item = steps[0].items[0];
36	  const itemPrice = BASE_PRICE[item.type] * itemModifierMultiplier(item);
37	  const loyaltyMultiplier =
38	    customer.yearsWithMHPCO >= 2 ? LOYALTY_MULTIPLIER : 1;
39	  const premium =
40	    ceilInMhpcoFavor(itemPrice * loyaltyMultiplier * FIRST_INSURANCE_MULTIPLIER) +
41	    ADMIN_FEE;
42	  return { results: [{ premium }] };
43	}
